with open("/root/books/webapp/books.json") as f:
    books = json.load(f)

book_map = {b["id"]: b for b in books}
updated = 0
for book_id, thoughts in updates.items():
    if book_id in book_map:
        book_map[book_id]["thoughts"] = thoughts
        updated += 1
        print(f"Обновлена: {book_id} {book_map[book_id]['title']}")

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))

print(f"Всего обновлено: {updated}")
print(f"Итого книг: {len(books)}")
